package gonameparts

import (
	"testing"
)

func TestSlot(t *testing.T) {
	t.Parallel()

	testCases := []struct {
		name     string
		part     string
		value    string
		expected string
		field    string
	}{
		{
			name:     "Set salutation",
			part:     "salutation",
			value:    "Dr.",
			expected: "Dr.",
			field:    "Salutation",
		},
		{
			name:     "Set generation",
			part:     "generation",
			value:    "Jr.",
			expected: "Jr.",
			field:    "Generation",
		},
		{
			name:     "Set suffix",
			part:     "suffix",
			value:    "Esq.",
			expected: "Esq.",
			field:    "Suffix",
		},
		{
			name:     "Set middle name",
			part:     "middle",
			value:    "Robert",
			expected: "Robert",
			field:    "MiddleName",
		},
		{
			name:     "Set last name",
			part:     "last",
			value:    "Smith",
			expected: "Smith",
			field:    "LastName",
		},
		{
			name:     "Set first name",
			part:     "first",
			value:    "John",
			expected: "John",
			field:    "FirstName",
		},
		{
			name:     "Unknown part",
			part:     "unknown",
			value:    "Value",
			expected: "",
			field:    "none",
		},
	}

	for _, tc := range testCases {
		tc := tc // capture range variable
		t.Run(tc.name, func(t *testing.T) {
			t.Parallel()
			p := &NameParts{}
			p.slot(tc.part, tc.value)

			var actual string
			switch tc.field {
			case "Salutation":
				actual = p.Salutation
			case "Generation":
				actual = p.Generation
			case "Suffix":
				actual = p.Suffix
			case "MiddleName":
				actual = p.MiddleName
			case "LastName":
				actual = p.LastName
			case "FirstName":
				actual = p.FirstName
			default:
				// For "none" field, we just verify nothing was changed
				if p.Salutation != "" || p.Generation != "" || p.Suffix != "" || 
				   p.MiddleName != "" || p.LastName != "" || p.FirstName != "" {
					t.Errorf("Expected no fields to be set, but some were")
				}
				return
			}

			if actual != tc.expected {
				t.Errorf("Expected '%s' to be '%s', but got '%s'", tc.field, tc.expected, actual)
			}
		})
	}
}

