impl NameString {
    pub(crate) fn split_aliases(&mut self, alias_sep: &str) -> Result<(), Error> {
        let split_names = self.split();

        let mut transformed_names = Vec::new();
        for part in &split_names {
            if part.to_uppercase() == alias_sep.to_uppercase() {
                transformed_names.push("*|*".to_string());
            } else {
                transformed_names.push(part.clone());
            }
        }

        let joined = transformed_names.join(" ");
        let names: Vec<String> = joined.split("*|*")
            .map(|s| s.to_string())
            .collect();

        if names.is_empty() {
            return Err(Error::new(ErrorKind::InvalidData, "No names found after splitting"));
        }

        self.full_name = names[0].clone();
        self.aliases = names[1..].to_vec();

        Ok(())
    }
}
