package gonameparts

import (
	"testing"
)

func TestParseTricky(t *testing.T) {
	testCases := []struct {
		name     string
		input    string
		expected NameParts
	}{
		{
			name:  "Nested AKA",
			input: "James Polera a/k/a Batman a/k/a Bruce Wayne",
			expected: NameParts{
				ProvidedName: "James Polera a/k/a Batman a/k/a Bruce Wayne",
				FirstName:    "James",
				LastName:     "Polera",
				Aliases: []NameParts{
					{
						ProvidedName: "Batman",
						FirstName:    "Batman",
						FullName:     "Batman",
					},
					{
						ProvidedName: "Bruce Wayne",
						FirstName:    "Bruce",
						LastName:     "Wayne",
						FullName:     "Bruce Wayne",
					},
				},
				FullName: "James Polera",
			},
		},
		{
			name:  "Complex Name with Suffix and Generation",
			input: "Mr. John Jacob Jingleheimer Schmidt III Esq.",
			expected: NameParts{
				ProvidedName: "Mr. John Jacob Jingleheimer Schmidt III Esq.",
				Salutation:   "Mr.",
				FirstName:    "John",
				MiddleName:   "Jacob Jingleheimer",
				LastName:     "Schmidt",
				Generation:   "III",
				Suffix:       "Esq.",
				FullName:     "Mr. John Jacob Jingleheimer Schmidt III Esq.",
			},
		},
		{
			name:  "Last Name Prefix",
			input: "Ludwig von Beethoven Jr.",
			expected: NameParts{
				ProvidedName: "Ludwig von Beethoven Jr.",
				FirstName:    "Ludwig",
				LastName:     "von Beethoven",
				Generation:   "Jr.",
				FullName:     "Ludwig von Beethoven Jr.",
			},
		},
		{
			name:  "Bad Apostrophe",
			input: "John O' Malley",
			expected: NameParts{
				ProvidedName: "John O' Malley",
				FirstName:    "John",
				LastName:     "O'Malley",
				FullName:     "John O'Malley",
			},
		},
		{
			name:  "Recursive Nickname with AKA",
			input: "Philip 'The Scooter' Rizzuto a/k/a 'Scooter'",
			expected: NameParts{
				ProvidedName: "Philip 'The Scooter' Rizzuto a/k/a 'Scooter'",
				FirstName:    "Philip",
				LastName:     "Rizzuto",
				Nickname:     "'The Scooter'",
				Aliases: []NameParts{
					{
						ProvidedName: "'Scooter'",
						Nickname:     "'Scooter'",
						FullName:     "",
					},
				},
				FullName: "Philip Rizzuto",
			},
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			result := Parse(tc.input)

			// Check first level fields
			if result.FirstName != tc.expected.FirstName {
				t.Errorf("FirstName mismatch: got %q, want %q", result.FirstName, tc.expected.FirstName)
			}
			if result.LastName != tc.expected.LastName {
				t.Errorf("LastName mismatch: got %q, want %q", result.LastName, tc.expected.LastName)
			}
			if result.Nickname != tc.expected.Nickname {
				t.Errorf("Nickname mismatch: got %q, want %q", result.Nickname, tc.expected.Nickname)
			}
			if result.Salutation != tc.expected.Salutation {
				t.Errorf("Salutation mismatch: got %q, want %q", result.Salutation, tc.expected.Salutation)
			}
			if result.Generation != tc.expected.Generation {
				t.Errorf("Generation mismatch: got %q, want %q", result.Generation, tc.expected.Generation)
			}
			if result.Suffix != tc.expected.Suffix {
				t.Errorf("Suffix mismatch: got %q, want %q", result.Suffix, tc.expected.Suffix)
			}
			if result.MiddleName != tc.expected.MiddleName {
				t.Errorf("MiddleName mismatch: got %q, want %q", result.MiddleName, tc.expected.MiddleName)
			}

			// Check aliases count
			if len(result.Aliases) != len(tc.expected.Aliases) {
				t.Errorf("Aliases count mismatch: got %d, want %d", len(result.Aliases), len(tc.expected.Aliases))
			} else {
				// Check each alias
				for i, alias := range result.Aliases {
					if alias.FirstName != tc.expected.Aliases[i].FirstName {
						t.Errorf("Alias[%d].FirstName mismatch: got %q, want %q", i, alias.FirstName, tc.expected.Aliases[i].FirstName)
					}
					if alias.LastName != tc.expected.Aliases[i].LastName {
						t.Errorf("Alias[%d].LastName mismatch: got %q, want %q", i, alias.LastName, tc.expected.Aliases[i].LastName)
					}
					if alias.Nickname != tc.expected.Aliases[i].Nickname {
						t.Errorf("Alias[%d].Nickname mismatch: got %q, want %q", i, alias.Nickname, tc.expected.Aliases[i].Nickname)
					}
				}
			}
		})
	}
}

